package foxglove_msgs

import (
    "github.com/bluenviron/goroslib/v2/pkg/msg"
    "time"
)


const (
    Log_UNKNOWN uint8 = 0
    Log_DEBUG uint8 = 1
    Log_INFO uint8 = 2
    Log_WARNING uint8 = 3
    Log_ERROR uint8 = 4
    Log_FATAL uint8 = 5
)

type Log struct {
    msg.Package `ros:"foxglove_msgs"`
    msg.Definitions `ros:"uint8 UNKNOWN=0,uint8 DEBUG=1,uint8 INFO=2,uint8 WARNING=3,uint8 ERROR=4,uint8 FATAL=5"`
    Timestamp time.Time
    Level uint8
    Message string
    Name string
    File string
    Line uint32
}

